  @use call    midiManager.setLength  @ open:110
  @use call    modalHost.registerKind  @ 157
  @use call    scratch.track  @ open:105 close:123
  @use call    trackerManager.bindTake  @ open:107 close:122
  @use call    trackerManager.currentTake  @ currentTake:128
  @use call    util.instantiate  @ 30,31,32,33,34,35,36,37,43
  @use require commandManager  @ 36
  @use require configManager  @ 31
  @use require dataStore  @ 32
  @use require eventMeta  @ 33
  @use require gridPane  @ 43
  @use require imgui  @ 16
